exec('from pathlib import Path\nfrom app.main import analyze_text,write_exports\nsample=chr(10).join(["所在地: 東京都サンプル区1-2-3","土地面積: 180.25㎡","用途地域: 第一種住居地域","建ぺい率: 60%","容積率: 300%","前面道路幅員: 4.0m","平均住戸面積: 45㎡"])\npaths=write_exports("sample",analyze_text(sample),sample,Path("property-ocr-outputs"))\nfor k,v in paths.items():\n    print(f"generated {k}: {v}")\n')